import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import type { PropertyValueMap, PropertyValues } from "@umbraco-cms/backoffice/external/lit";
import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
  queryAsync,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import type {
  Field,
  FieldTypeWithSettings,
  FormDesign,
  FormSecurityForUser,
} from "@umbraco-forms/generated";
import { FORMS_CONTEXT } from "@umbraco-forms/context";
import type {
  UUISelectElement,
  UUISelectEvent,
} from "@umbraco-cms/backoffice/external/uui";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../form-workspace.context-token.js";
import {
  FORMS_STRUCTURE_MANAGER,
  FormStructureManager,
} from "../../form-structure-manager.class.js";
import { FormsFieldTypeCollectionRepository } from "../../../../provider-types/field-types/repository/collection/index.js";
import type { FormsFormPageElement } from "./components/forms-form-page.design.element.js";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";

const elementName = "workspace-view-form-design";

@customElement(elementName)
export class UmbWorkspaceViewFormDesignElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  @state()
  _form?: FormDesign;

  @state()
  _userSecurity?: FormSecurityForUser;

  @state()
  _sortModeActive = false;

  @queryAsync("forms-form-page")
  _pagesPromise?: Promise<FormsFormPageElement>;

  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;
  #formsContext!: typeof FORMS_CONTEXT.TYPE;
  #structureManager?: FormStructureManager;

  #init?: Promise<unknown>;

  #allFields: Array<Field> = [];
  #allFieldTypes: Array<FieldTypeWithSettings> = [];

  constructor() {
    super();

    this.#init = Promise.all([
      this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
        this.#workspaceContext = instance;
      }).asPromise(),

      this.consumeContext(FORMS_CONTEXT, (context) => {
        this.#formsContext = context;
      }).asPromise(),
    ]);

    this.#initialize();
  }

  async #initialize() {
    await this.#init;
    if (!this.#workspaceContext) return;

    this.#structureManager = new FormStructureManager(
      this,
      this.#workspaceContext
    );
    this.provideContext(FORMS_STRUCTURE_MANAGER, this.#structureManager);

    const repository = new FormsFieldTypeCollectionRepository(this);
    const { data } = await repository.requestCollection();
    this.#allFieldTypes = data?.items || [];

    this.observe(this.#workspaceContext.data, (form) => {
      if (!form) return;
      this._form = form;

      if (this.#workspaceContext) {
        this.#allFields = this.#workspaceContext?.getAllFields();
      }

      this.#setUpPageScrollObserver();
    });

    this.observe(this.#formsContext.userSecurity, (userSecurity) => {
      this._userSecurity = userSecurity;
    });
  }

  #onAddPageClick(addToTop: boolean) {
    this.#structureManager?.addFormPage(addToTop);
  }

  #onReorderClick() {
    this._sortModeActive = !this._sortModeActive;
    this.#scrollToActivePageIndex();
  }

  #activePageIndex: number = -1;
  #disableVisiblePageTracking: boolean = false;
  #pageCount: number = -1;

  async #setUpPageScrollObserver() {
    if (!this._form) return;

    // The queryAsync decorator returns a promise which resolves when the queried element is available
    // We can await that promise to ensure the pages have rendered, then use querySelectorAll to get the full set
    await this._pagesPromise;

    // If we haven't changed the number of pages since the last setup, no need to do it again.
    if (this.#pageCount > 0 && this._form.pages.length === this.#pageCount)
      return;

    const options = {
      root: null,
      threshold: 0.1,
    };

    const callback = (entries) => {
      if (!this.#disableVisiblePageTracking) {
        const pageIndexes = entries
          .filter((e) => e.isIntersecting)
          .map((e) => e.target.getAttribute("data-page-index"));
        pageIndexes.forEach((pageIndex) => {
          if (!pageIndex) {
            return;
          }
          this.#activePageIndex = pageIndex;
        });
      }
    };

    const observer = new IntersectionObserver(callback, options);

    const pages = this.renderRoot.querySelectorAll("forms-form-page");
    this.#pageCount = pages.length;

    pages.forEach((page) => {
      observer.observe(page);
    });
  }

  #scrollToActivePageIndex() {
    if (this.#activePageIndex >= 0) {
      const pageElement = this.shadowRoot!.querySelector(
        "forms-form-page[data-page-index='" + this.#activePageIndex + "']"
      );
      if (pageElement) {
        this.#scrollToPage(pageElement);
      }
    }
  }

  #getPageNumberOptions() {
    const options =
      this._form?.pages.map((p, i) => ({
        name: (i + 1).toString(),
        value: i.toString(),
        selected: false,
      })) ?? [];
    options.unshift({
      name: this.localize.term("formEdit_jumpToPage"),
      value: "",
      selected: true,
    });
    return options;
  }

  #onJumpToPageChange(e: UUISelectEvent) {
    const element = e.target as UUISelectElement;
    const value = element.value.toString();
    if (value !== "") {
      const pageElement = this.shadowRoot!.querySelector(
        "forms-form-page[data-page-index='" + value + "']"
      );
      if (pageElement) {
        this.#scrollToPage(pageElement);
      }
    }

    this.#resetJumpToPageOptions(element);
  }

  #scrollToPage(element: Element) {
    this.#disableVisiblePageTracking = true;
    element.scrollIntoView();
    this.#disableVisiblePageTracking = false;
  }

  #resetJumpToPageOptions(element: UUISelectElement) {
    for (let index = 0; index < element.options.length; index++) {
      const option = element.options[index];
      option.selected = false;
    }
    element.options[0].selected = true;
    this.requestUpdate();
  }

  render() {
    return html`
      <div id="formHeader">
        <div class="actions">
          ${when(
            !this._sortModeActive,
            () => html`
              <uui-button-group>
                <uui-button
                  look="placeholder"
                  label=${this.localize.term("formEdit_addToTop")}
                  @click=${() => this.#onAddPageClick(true)}
                >
                  ${this.localize.term("formEdit_addToTop")}
                </uui-button>
                <uui-button
                  look="placeholder"
                  label=${this.localize.term("formEdit_addToBottom")}
                  @click=${() => this.#onAddPageClick(false)}
                >
                  ${this.localize.term("formEdit_addToBottom")}
                </uui-button>
              </uui-button-group>`
          )}

          <uui-button
            @click=${this.#onReorderClick}
            compact
            look="outline"
            label=${this.localize.term(
              this._sortModeActive ? "general_reorderDone" : "general_reorder"
            )}
          >
            <uui-icon name="icon-navigation"></uui-icon>
            ${this.localize.term(
              this._sortModeActive ? "general_reorderDone" : "general_reorder"
            )}
          </uui-button>

          ${when(
            this._form && this._form.pages.length > 1,
            () => html`
              <uui-select
                label=${this.localize.term("formEdit_jumpToPage")}
                name="jumpToPage"
                @change=${this.#onJumpToPageChange}
                .options=${this.#getPageNumberOptions()}
              >
              </uui-select>
            `
          )}
        </div>
      </div>

      <div id="formPages">
        ${this._form?.pages.map(
          (page, idx) =>
            html`<forms-form-page
              class="sort-mode-${this._sortModeActive ? "active" : "inactive"}"
              data-page-index="${idx}"
              .page=${page}
              .index=${idx}
              .allFields=${this.#allFields}
              .allFieldTypes=${this.#allFieldTypes}
              ?sort-mode-active=${this._sortModeActive}
            >
            </forms-form-page>`
        )}
      </div>

      <div id="formFooter">
        ${when(
          !this._sortModeActive,
          () => html` <uui-button
            @click=${() => this.#onAddPageClick(false)}
            look="outline"
            label=${this.localize.term("formEdit_addPage")}
          ></uui-button>`
        )}
      </div>

      ${when(
        !this._sortModeActive &&
          this._userSecurity?.userSecurity.manageWorkflows, // TODO: <-- ths doesn't work when we have group security enabled.
        () => html` <forms-form-workflow-summary
          .workflows=${this._form?.formWorkflows}
          .submitMessageDetail=${{
            messageOnSubmit: this._form?.messageOnSubmit,
            messageOnSubmitIsHtml: this._form?.messageOnSubmitIsHtml ?? false,
            goToPageOnSubmit: this._form?.goToPageOnSubmit,
          }}
          ?manualApproval=${this._form?.manualApproval}
          .allFields=${this.#allFields}
        ></forms-form-workflow-summary>`
      )}
    `;
  }

  static styles = [
    UmbTextStyles,
    css`
      :host {
        display: block;
        padding: var(--uui-size-layout-1);
      }

      #formHeader {
        position: sticky;
        top: 0;
        border: solid 1px #ccc;
        padding: 10px;
        background-color: #fff;
        z-index: 9;
      }

      #formHeader,
      actions {
        margin-bottom: var(--uui-size-5);
        display: flex;
        justify-content: flex-end;
        column-gap: var(--uui-size-3);
      }

      forms-form-page.sort-mode-inactive {
        scroll-margin-top: 80px;
      }

      forms-form-page.sort-mode-active {
        scroll-margin-top: 30px;
      }

      #formFooter {
        display: flex;
        align-items: center;
        justify-content: center;
        margin-bottom: 30px;
      }

      uui-button uui-icon {
        margin-right: var(--uui-size-2);
      }
    `,
  ];
}

export default UmbWorkspaceViewFormDesignElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewFormDesignElement;
  }
}
